import { useEffect, useState } from "react";
import { collection, onSnapshot, query, orderBy, addDoc, updateDoc, doc, getDoc, getDocs, increment } from "firebase/firestore";
import { ref, uploadBytesResumable, getDownloadURL } from "firebase/storage";
import { db, storage, isFirebaseConfigured } from "./firebase";

export interface Report {
  id: string;
  photoUrl: string;
  latitude: number;
  longitude: number;
  causeTag: 'dumping' | 'drain' | 'general';
  severity: 'low' | 'medium' | 'high';
  description: string;
  status: 'reported' | 'acknowledged' | 'cleaned';
  upvotes: number;
  createdAt: number;
  reporterEmail?: string;
}

const SEED_REPORTS: Report[] = [
  {
    id: '1',
    photoUrl: 'https://picsum.photos/400/300?random=1',
    latitude: 19.0990,
    longitude: 72.8260,
    causeTag: 'dumping',
    severity: 'high',
    description: 'Large pile of industrial waste and plastic bags dumped right beside Versova beach. Smell is unbearable.',
    status: 'reported',
    upvotes: 24,
    createdAt: Date.now() - 86400000,
  },
  {
    id: '2',
    photoUrl: 'https://picsum.photos/400/300?random=2',
    latitude: 18.9322,
    longitude: 72.8264,
    causeTag: 'drain',
    severity: 'medium',
    description: 'Broken sewage drain near Haji Ali discharging directly into the sea. Black water flowing continuously.',
    status: 'acknowledged',
    upvotes: 18,
    createdAt: Date.now() - 172800000,
  },
  {
    id: '3',
    photoUrl: 'https://picsum.photos/400/300?random=3',
    latitude: 19.0558,
    longitude: 72.8295,
    causeTag: 'general',
    severity: 'low',
    description: 'Heavy plastic and debris washed ashore at Juhu Beach after last night\'s rain. Urgent cleanup needed.',
    status: 'cleaned',
    upvotes: 31,
    createdAt: Date.now() - 259200000,
  },
  {
    id: '4',
    photoUrl: 'https://picsum.photos/400/300?random=4',
    latitude: 19.1020,
    longitude: 72.8654,
    causeTag: 'drain',
    severity: 'high',
    description: 'Broken manhole near Borivali creek overflowing with sewage after rain. Kids playing nearby are at serious risk.',
    status: 'reported',
    upvotes: 9,
    createdAt: Date.now() - 345600000,
  },
  {
    id: '5',
    photoUrl: 'https://picsum.photos/400/300?random=5',
    latitude: 18.9750,
    longitude: 72.8258,
    causeTag: 'dumping',
    severity: 'medium',
    description: 'Construction debris illegally dumped near Worli seaface. Materials are sliding into the water.',
    status: 'acknowledged',
    upvotes: 14,
    createdAt: Date.now() - 432000000,
  },
];

let mockReports: Report[] = [...SEED_REPORTS];
let listeners: Array<(data: Report[]) => void> = [];
const notifyListeners = () => listeners.forEach(l => l([...mockReports]));

const useMockFallback = (setReports: (r: Report[]) => void) => {
  setReports([...mockReports]);
  listeners.push(setReports);
  return () => {
    listeners = listeners.filter(l => l !== setReports);
  };
};

export const useReports = () => {
  const [reports, setReports] = useState<Report[]>([...SEED_REPORTS]);
  const [error, setError] = useState(false);

  useEffect(() => {
    if (!isFirebaseConfigured) {
      return useMockFallback(setReports);
    }

    let timedOut = false;
    const timeout = setTimeout(() => {
      timedOut = true;
      setError(true);
      setReports([...mockReports]);
    }, 5000);

    const q = query(collection(db, "reports"), orderBy("createdAt", "desc"));
    let unsub: (() => void) | undefined;
    try {
      unsub = onSnapshot(q, (snapshot) => {
        if (timedOut) return;
        clearTimeout(timeout);
        const data = snapshot.docs.map(d => ({ id: d.id, ...d.data() } as Report));
        setReports(data.length > 0 ? data : [...mockReports]);
      }, () => {
        clearTimeout(timeout);
        setReports([...mockReports]);
      });
    } catch {
      clearTimeout(timeout);
      setReports([...mockReports]);
    }
    return () => {
      clearTimeout(timeout);
      unsub?.();
    };
  }, []);

  return { reports, error };
};

export const api = {
  createReport: async (data: Omit<Report, 'id' | 'createdAt' | 'upvotes' | 'status' | 'photoUrl'>, file?: File | null) => {
    let photoUrl = `https://picsum.photos/400/300?random=${Math.floor(Math.random() * 100)}`;

    if (isFirebaseConfigured && file) {
      try {
        const fileRef = ref(storage, `reports/${Date.now()}_${file.name}`);
        const uploadResult = await uploadBytesResumable(fileRef, file);
        photoUrl = await getDownloadURL(uploadResult.ref);
      } catch {
        // Storage not configured — use placeholder
      }
    }

    const newReportData = {
      ...data,
      photoUrl,
      createdAt: Date.now(),
      upvotes: 0,
      status: 'reported' as const,
    };

    if (!isFirebaseConfigured) {
      const newReport: Report = { ...newReportData, id: Math.random().toString(36).substr(2, 9) };
      mockReports = [newReport, ...mockReports];
      notifyListeners();
      return newReport;
    }

    try {
      const docRef = await addDoc(collection(db, "reports"), newReportData);
      return { id: docRef.id, ...newReportData };
    } catch {
      const newReport: Report = { ...newReportData, id: Math.random().toString(36).substr(2, 9) };
      mockReports = [newReport, ...mockReports];
      notifyListeners();
      return newReport;
    }
  },

  upvoteReport: async (id: string) => {
    mockReports = mockReports.map(r => r.id === id ? { ...r, upvotes: r.upvotes + 1 } : r);
    notifyListeners();
    if (!isFirebaseConfigured) return;
    try {
      await updateDoc(doc(db, "reports", id), { upvotes: increment(1) });
    } catch { /* offline fallback already applied */ }
  },

  getReport: async (id: string): Promise<Report | undefined> => {
    const local = mockReports.find(r => r.id === id);
    if (!isFirebaseConfigured) return local;
    try {
      const snapshot = await getDoc(doc(db, "reports", id));
      if (snapshot.exists()) return { id: snapshot.id, ...snapshot.data() } as Report;
    } catch { /* fall through */ }
    return local;
  },

  getStats: async () => {
    const compute = (list: Report[]) => ({
      total: list.length,
      dumping: list.filter(r => r.causeTag === 'dumping').length,
      drain: list.filter(r => r.causeTag === 'drain').length,
      general: list.filter(r => r.causeTag === 'general').length,
      reported: list.filter(r => r.status === 'reported').length,
      acknowledged: list.filter(r => r.status === 'acknowledged').length,
      cleaned: list.filter(r => r.status === 'cleaned').length,
    });

    if (!isFirebaseConfigured) return compute(mockReports);

    try {
      const snapshot = await Promise.race([
        getDocs(collection(db, "reports")),
        new Promise<never>((_, reject) => setTimeout(() => reject(new Error('timeout')), 5000)),
      ]) as Awaited<ReturnType<typeof getDocs>>;
      const all = snapshot.docs.map(d => d.data() as Report);
      return compute(all.length > 0 ? all : mockReports);
    } catch {
      return compute(mockReports);
    }
  },
};

