import { useEffect, useState } from "react";
import { api } from "@/lib/db";
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend, BarChart, Bar, XAxis, YAxis, CartesianGrid } from "recharts";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Activity, AlertTriangle, CheckCircle2, ShieldAlert, Clock, Waves } from "lucide-react";

interface Stats {
  total: number;
  dumping: number;
  drain: number;
  general: number;
  reported: number;
  acknowledged: number;
  cleaned: number;
}

const MOCK_STATS: Stats = {
  total: 5,
  dumping: 2,
  drain: 2,
  general: 1,
  reported: 2,
  acknowledged: 2,
  cleaned: 1,
};

const WEEKLY_DATA = [
  { day: 'Mon', reports: 2 },
  { day: 'Tue', reports: 4 },
  { day: 'Wed', reports: 1 },
  { day: 'Thu', reports: 3 },
  { day: 'Fri', reports: 5 },
  { day: 'Sat', reports: 7 },
  { day: 'Sun', reports: 3 },
];

const CAUSE_COLORS: Record<string, string> = {
  'Illegal Dumping': '#f97316',
  'Broken Drains': '#3b82f6',
  'General Pollution': '#22c55e',
};

export default function Dashboard() {
  const [stats, setStats] = useState<Stats>(MOCK_STATS);

  useEffect(() => {
    api.getStats().then(s => setStats(s as Stats)).catch(() => {});
  }, []);

  const resolutionRate = stats.total > 0 ? Math.round((stats.cleaned / stats.total) * 100) : 0;

  const pieData = [
    { name: 'Illegal Dumping', value: stats.dumping, color: '#f97316' },
    { name: 'Broken Drains', value: stats.drain, color: '#3b82f6' },
    { name: 'General Pollution', value: stats.general, color: '#22c55e' },
  ].filter(d => d.value > 0);

  const statusData = [
    { name: 'Reported', value: stats.reported, color: '#94a3b8' },
    { name: 'Acknowledged', value: stats.acknowledged, color: '#f59e0b' },
    { name: 'Cleaned', value: stats.cleaned, color: '#22c55e' },
  ];

  return (
    <div className="max-w-6xl mx-auto p-4 md:p-6 py-8">
      <div className="mb-8">
        <h1 className="text-3xl font-bold">Impact Dashboard</h1>
        <p className="text-muted-foreground mt-1">Aggregated data from all citizen reports. Protecting our coastlines together.</p>
      </div>

      {/* Stat cards */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-8">
        <Card>
          <CardContent className="p-5 flex flex-col gap-2">
            <Activity className="w-7 h-7 text-primary" />
            <div className="text-4xl font-bold mt-1">{stats.total}</div>
            <div className="text-sm text-muted-foreground">Total Reports</div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-5 flex flex-col gap-2">
            <AlertTriangle className="w-7 h-7 text-orange-500" />
            <div className="text-4xl font-bold mt-1">{stats.dumping}</div>
            <div className="text-sm text-muted-foreground">Dumping Incidents</div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-5 flex flex-col gap-2">
            <ShieldAlert className="w-7 h-7 text-blue-500" />
            <div className="text-4xl font-bold mt-1">{stats.drain}</div>
            <div className="text-sm text-muted-foreground">Broken Drains</div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-5 flex flex-col gap-2">
            <CheckCircle2 className="w-7 h-7 text-green-500" />
            <div className="text-4xl font-bold mt-1">{resolutionRate}%</div>
            <div className="text-sm text-muted-foreground">Resolution Rate</div>
          </CardContent>
        </Card>
      </div>

      {/* Charts row */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-6">
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2"><Waves className="w-5 h-5" /> Reports by Cause</CardTitle>
          </CardHeader>
          <CardContent className="h-[280px]">
            {pieData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie data={pieData} cx="50%" cy="50%" innerRadius={65} outerRadius={100} paddingAngle={4} dataKey="value">
                    {pieData.map((entry, i) => (
                      <Cell key={i} fill={entry.color} />
                    ))}
                  </Pie>
                  <Tooltip formatter={(v: number) => [`${v} reports`, '']} />
                  <Legend verticalAlign="bottom" height={36} formatter={(value) => <span style={{ color: CAUSE_COLORS[value] || '#64748b' }}>{value}</span>} />
                </PieChart>
              </ResponsiveContainer>
            ) : (
              <div className="h-full flex items-center justify-center text-muted-foreground">No data yet</div>
            )}
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2"><Activity className="w-5 h-5" /> Weekly Activity</CardTitle>
          </CardHeader>
          <CardContent className="h-[280px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={WEEKLY_DATA} margin={{ top: 5, right: 10, left: -20, bottom: 5 }}>
                <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                <XAxis dataKey="day" tick={{ fontSize: 12 }} />
                <YAxis tick={{ fontSize: 12 }} />
                <Tooltip />
                <Bar dataKey="reports" fill="hsl(var(--primary))" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </CardContent>
        </Card>
      </div>

      {/* Status breakdown */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2"><Clock className="w-5 h-5" /> Status Breakdown</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="flex flex-col md:flex-row gap-6">
            {statusData.map(s => (
              <div key={s.name} className="flex-1">
                <div className="flex justify-between mb-2">
                  <span className="text-sm font-medium">{s.name}</span>
                  <span className="text-sm font-bold">{s.value}</span>
                </div>
                <div className="h-2 rounded-full bg-muted overflow-hidden">
                  <div
                    className="h-full rounded-full transition-all duration-700"
                    style={{
                      width: stats.total > 0 ? `${Math.round((s.value / stats.total) * 100)}%` : '0%',
                      backgroundColor: s.color,
                    }}
                  />
                </div>
                <p className="text-xs text-muted-foreground mt-1">
                  {stats.total > 0 ? Math.round((s.value / stats.total) * 100) : 0}% of total
                </p>
              </div>
            ))}
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

