                <span>{item.label}</span>
                {active && <div className="ml-auto w-1.5 h-1.5 rounded-full bg-primary" />}
              </Link>
            );
          })}
        </nav>

        <div className="p-4 border-t">
          <div className="text-[10px] text-muted-foreground text-center leading-relaxed">
            Reports route to MCGM &amp; MPCB<br />
            Contact: <a href="mailto:riplle.team@gmail.com" className="text-primary hover:underline">riplle.team@gmail.com</a>
          </div>
        </div>
      </aside>

      {/* Main */}
      <main className="flex-1 pb-16 md:pb-0 min-h-screen overflow-x-hidden">
        {children}
      </main>

      {/* Mobile Bottom Nav */}
      <nav className="md:hidden fixed bottom-0 inset-x-0 bg-card/95 backdrop-blur border-t z-50 safe-area-pb">
        <div className="flex justify-around items-center px-1 py-1">
          {mobileNav.map((item) => {
            const active = location === item.href || (item.href !== "/" && location.startsWith(item.href));
            if (item.cta) {
              return (
                <Link key={item.href} href={item.href}
                  className="flex flex-col items-center gap-0.5 -mt-3"
                >
                  <div className="w-12 h-12 rounded-2xl gradient-ocean flex items-center justify-center shadow-lg">
                    <item.icon className="w-5 h-5 text-white" strokeWidth={2.5} />
                  </div>
                  <span className="text-[9px] font-semibold text-primary">Report</span>
                </Link>
              );
            }
            return (
              <Link key={item.href} href={item.href}
                className={cn(
                  "flex flex-col items-center gap-1 p-2 rounded-xl min-w-[48px] transition-all",
                  active ? "text-primary" : "text-muted-foreground"
                )}
              >
                <item.icon className="w-5 h-5" />
                <span className="text-[9px] font-semibold">{item.label}</span>
              </Link>
            );
          })}
        </div>
      </nav>
    </div>
  );
}

