const CAUSE_COLORS = { Illegal_Dumping: "#f97316", Broken_Drains: "#3b82f6", General_Pollution: "#22c55e" };

function StatCard({ icon: Icon, value, label, color, suffix = "" }: { icon: any; value: number; label: string; color: string; suffix?: string }) {
  return (
    <Card className="gradient-card-hover">
      <CardContent className="p-5 flex flex-col gap-3">
        <div className={cn("w-10 h-10 rounded-xl flex items-center justify-center", color)}>
          <Icon className="w-5 h-5 text-white" />
        </div>
        <div>
          <div className="text-3xl font-extrabold">{value}{suffix}</div>
          <div className="text-xs text-muted-foreground font-medium mt-0.5">{label}</div>
        </div>
      </CardContent>
    </Card>
  );
}

