const RSS2JSON = "https://api.rss2json.com/v1/api.json?rss_url=";

const FALLBACK_NEWS: NewsItem[] = [
  {
    title: "Microplastics found in human blood for first time — scientists alarmed",
    description: "Researchers in Amsterdam found microplastic particles in the blood of 80% of the 22 people they tested. The discovery raises new questions about the impact of plastic pollution on human health.",
