const CATEGORY_COLORS: Record<string, string> = {
  Global: "bg-blue-100 text-blue-700 dark:bg-blue-950 dark:text-blue-300",
  India: "bg-orange-100 text-orange-700 dark:bg-orange-950 dark:text-orange-300",
  Mumbai: "bg-emerald-100 text-emerald-700 dark:bg-emerald-950 dark:text-emerald-300",
};

export default function News() {
  const [items, setItems] = useState<NewsItem[]>(FALLBACK_NEWS);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(false);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);

  const fetchNews = async () => {
    setLoading(true);
    setError(false);

    const allItems: NewsItem[] = [];

    await Promise.allSettled(
      SOURCES.map(async (src) => {
        const res = await fetch(`${RSS2JSON}${encodeURIComponent(src.url)}&count=6`);
        const data = await res.json();
        if (data.status === "ok" && Array.isArray(data.items)) {
          data.items.forEach((item: any) => {
            allItems.push({
              title: item.title || "",
              description: item.description?.replace(/<[^>]*>/g, "").slice(0, 200) || "",
              link: item.link || "",
              pubDate: item.pubDate || new Date().toISOString(),
              thumbnail: item.thumbnail || item.enclosure?.link,
              source: src.name.split("–")[0].trim(),
              category: src.category,
            });
          });
        }
      })
    );

    if (allItems.length > 0) {
      setItems(allItems.sort((a, b) => new Date(b.pubDate).getTime() - new Date(a.pubDate).getTime()));
      setError(false);
    } else {
      setItems(FALLBACK_NEWS);
      setError(true);
    }
    setLastUpdated(new Date());
    setLoading(false);
  };

  useEffect(() => { fetchNews(); }, []);

  return (
    <div className="max-w-4xl mx-auto p-4 md:p-6 py-8">
      {/* Header */}
      <div className="flex items-start justify-between mb-6">
        <div>
          <h1 className="text-3xl font-extrabold">Environmental News</h1>
          <p className="text-muted-foreground text-sm mt-1">
            Global pollution updates from The Guardian, BBC, and more.
          </p>
        </div>
        <Button variant="outline" size="sm" onClick={fetchNews} disabled={loading} className="gap-2 shrink-0">
          <RefreshCw className={cn("w-3.5 h-3.5", loading && "animate-spin")} />
          Refresh
        </Button>
      </div>

      {error && (
        <div className="flex items-center gap-3 bg-amber-50 dark:bg-amber-950/30 border border-amber-200 dark:border-amber-800 rounded-xl p-4 mb-6 text-sm text-amber-700 dark:text-amber-400">
          <AlertCircle className="w-4 h-4 shrink-0" />
          Showing curated articles — live feed temporarily unavailable. Refresh to retry.
        </div>
      )}

      {lastUpdated && !loading && (
        <div className="flex items-center gap-2 text-xs text-muted-foreground mb-5">
          <Globe className="w-3.5 h-3.5" />
          Updated {formatDistanceToNow(lastUpdated, { addSuffix: true })}
        </div>
      )}

      {/* Loading state */}
      {loading && (
        <div className="space-y-4">
          {[...Array(5)].map((_, i) => (
            <div key={i} className="animate-pulse flex gap-4 p-4 bg-card border rounded-xl">
              <div className="w-28 h-20 bg-muted rounded-lg shrink-0" />
              <div className="flex-1 space-y-2 py-1">
                <div className="h-4 bg-muted rounded w-4/5" />
                <div className="h-3 bg-muted rounded w-full" />
                <div className="h-3 bg-muted rounded w-3/5" />
              </div>
            </div>
          ))}
        </div>
      )}

      {/* News items */}
      {!loading && (
        <div className="space-y-4">
          {items.map((item, i) => {
            let date: Date | null = null;
            try { date = new Date(item.pubDate); } catch { }

            return (
              <a
                key={i}
                href={item.link}
                target="_blank"
                rel="noopener noreferrer"
                className="flex gap-4 p-4 bg-card border rounded-xl hover:border-primary/40 hover:shadow-md transition-all group"
                data-testid={`news-item-${i}`}
              >
                {item.thumbnail && (
                  <img
                    src={item.thumbnail}
                    alt=""
                    className="w-28 h-20 object-cover rounded-lg shrink-0 bg-muted"
                    onError={e => { (e.target as HTMLImageElement).style.display = "none"; }}
                  />
                )}
                <div className="flex-1 min-w-0">
                  <div className="flex gap-2 mb-2 flex-wrap">
                    <Badge variant="outline" className={cn("text-[10px] px-2 py-0.5 font-semibold", CATEGORY_COLORS[item.category] || "")}>
                      {item.category}
                    </Badge>
                    <span className="text-[10px] text-muted-foreground">{item.source}</span>
                    {date && <span className="text-[10px] text-muted-foreground">{formatDistanceToNow(date, { addSuffix: true })}</span>}
                  </div>
                  <h3 className="font-semibold text-sm leading-snug mb-1 group-hover:text-primary transition-colors line-clamp-2">
                    {item.title}
                  </h3>
                  <p className="text-xs text-muted-foreground line-clamp-2">{item.description}</p>
                </div>
                <ExternalLink className="w-4 h-4 text-muted-foreground shrink-0 mt-1 opacity-0 group-hover:opacity-100 transition-opacity" />
              </a>
            );
          })}
        </div>
      )}
    </div>
  );
}

import { Switch, Route, Router as WouterRouter } from "wouter";
import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
import { Layout } from "@/components/Layout";
import Home from "@/pages/Home";
import MapPage from "@/pages/MapPage";
import ReportForm from "@/pages/ReportForm";
import ReportsList from "@/pages/ReportsList";
import ReportDetail from "@/pages/ReportDetail";
import Dashboard from "@/pages/Dashboard";
import News from "@/pages/News";
import Authorities from "@/pages/Authorities";
import ActionGallery from "@/pages/ActionGallery";

const queryClient = new QueryClient();

function Router() {
  return (
    <Layout>
      <Switch>
        <Route path="/" component={Home} />
        <Route path="/map" component={MapPage} />
        <Route path="/report" component={ReportForm} />
        <Route path="/reports" component={ReportsList} />
        <Route path="/report/:id" component={ReportDetail} />
