}

import { useReports } from "@/lib/db";
import { Map } from "@/components/Map";
import { useState } from "react";
import { Trash2, Droplets, Waves, Filter, X } from "lucide-react";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";

type Cause = "all" | "dumping" | "drain" | "general";
type Severity = "all" | "low" | "medium" | "high";
type Status = "all" | "reported" | "acknowledged" | "cleaned";

const CAUSES = [
  { id: "all",     label: "All Reports",       icon: Filter,  color: "bg-primary text-primary-foreground" },
  { id: "dumping", label: "Illegal Dumping",   icon: Trash2,  color: "bg-orange-500 text-white" },
  { id: "drain",   label: "Broken Drains",     icon: Droplets,color: "bg-blue-500 text-white" },
  { id: "general", label: "General Pollution", icon: Waves,   color: "bg-green-500 text-white" },
] as const;

export default function MapPage() {
  const { reports, ready } = useReports();
  const [cause, setCause] = useState<Cause>("all");
  const [severity, setSeverity] = useState<Severity>("all");
  const [status, setStatus] = useState<Status>("all");
  const [open, setOpen] = useState(true);

  const filtered = reports.filter(r => {
    if (cause !== "all" && r.causeTag !== cause) return false;
    if (severity !== "all" && r.severity !== severity) return false;
    if (status !== "all" && r.status !== status) return false;
    return true;
  });

  return (
    <div className="relative w-full h-[calc(100vh-56px)] md:h-screen overflow-hidden">
      {/* Map fills entire container */}
      <div className="absolute inset-0">
        {ready ? (
          <Map reports={filtered} height="100%" zoom={12} flyToBounds />
        ) : (
          <div className="w-full h-full bg-muted flex items-center justify-center">
            <div className="text-muted-foreground animate-pulse">Loading map…</div>
          </div>
        )}
      </div>

      {/* Filter panel */}
      <div className={cn(
        "absolute top-4 left-4 z-[500] bg-card/95 backdrop-blur border rounded-2xl shadow-xl transition-all",
        open ? "w-72" : "w-14"
      )}>
        <div className="flex items-center justify-between p-3 border-b">
          {open && <h2 className="font-bold text-sm">Filters</h2>}
          <Button variant="ghost" size="icon" className="w-8 h-8 ml-auto" onClick={() => setOpen(!open)}>
            {open ? <X className="w-4 h-4" /> : <Filter className="w-4 h-4" />}
          </Button>
        </div>

        {open && (
          <div className="p-3 space-y-4">
            {/* Cause filter */}
            <div>
              <label className="text-[10px] font-bold text-muted-foreground uppercase tracking-wide mb-2 block">Cause</label>
              <div className="flex flex-col gap-1.5">
                {CAUSES.map(c => {
                  const active = cause === c.id;
                  return (
                    <button
                      key={c.id}
                      onClick={() => setCause(c.id as Cause)}
                      className={cn(
                        "flex items-center gap-2.5 px-3 py-2 rounded-lg text-xs font-medium transition-all text-left",
                        active ? c.color + " shadow-sm" : "hover:bg-muted text-foreground"
                      )}
                    >
                      <c.icon className="w-3.5 h-3.5 shrink-0" />
                      {c.label}
                    </button>
                  );
                })}
              </div>
            </div>

            {/* Severity filter */}
            <div>
              <label className="text-[10px] font-bold text-muted-foreground uppercase tracking-wide mb-2 block">Severity</label>
              <div className="flex gap-1.5">
                {(["all", "low", "medium", "high"] as Severity[]).map(s => (
                  <button
                    key={s}
                    onClick={() => setSeverity(s)}
                    className={cn(
                      "flex-1 py-1.5 rounded-lg text-[10px] font-semibold capitalize transition-all",
                      severity === s ? "bg-primary text-primary-foreground shadow-sm" : "bg-muted hover:bg-muted/80"
                    )}
                  >
                    {s}
                  </button>
                ))}
              </div>
            </div>

            {/* Status filter */}
            <div>
              <label className="text-[10px] font-bold text-muted-foreground uppercase tracking-wide mb-2 block">Status</label>
              <div className="flex flex-col gap-1">
                {(["all", "reported", "acknowledged", "cleaned"] as Status[]).map(s => (
                  <button
                    key={s}
                    onClick={() => setStatus(s)}
                    className={cn(
                      "px-3 py-1.5 rounded-lg text-[10px] font-semibold capitalize transition-all text-left",
                      status === s ? "bg-primary text-primary-foreground" : "hover:bg-muted"
                    )}
                  >
                    {s === "all" ? "All statuses" : s}
                  </button>
                ))}
              </div>
            </div>

            {/* Count */}
            <div className="pt-1 border-t text-center text-xs text-muted-foreground">
              Showing <span className="font-bold text-foreground">{filtered.length}</span> of {reports.length} reports
            </div>
          </div>
        )}
      </div>

      {/* Legend */}
      <div className="absolute bottom-6 right-4 z-[500] bg-card/95 backdrop-blur border rounded-xl p-3 shadow-lg text-xs space-y-1.5">
        <div className="font-bold text-[10px] text-muted-foreground uppercase tracking-wide mb-2">Legend</div>
        {[
          { color: "#f97316", label: "Illegal Dumping" },
          { color: "#3b82f6", label: "Broken Drain" },
          { color: "#22c55e", label: "General Pollution" },
        ].map(l => (
          <div key={l.label} className="flex items-center gap-2">
            <div className="w-3 h-3 rounded-full shrink-0" style={{ backgroundColor: l.color }} />
            <span>{l.label}</span>
          </div>
        ))}
        <div className="border-t pt-1.5 mt-1.5 text-[10px] text-muted-foreground">Larger pin = higher severity</div>
      </div>
    </div>
  );
}

import { useReports } from "@/lib/db";
import { Link } from "wouter";
import { Trash2, Droplets, Waves, MapPin, ThumbsUp, Search, SlidersHorizontal } from "lucide-react";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { useState } from "react";
import { formatDistanceToNow } from "date-fns";
import { cn } from "@/lib/utils";

const CAUSE = {
  dumping: { label: "Illegal Dumping", icon: Trash2,   badge: "bg-orange-100 text-orange-700 dark:bg-orange-950 dark:text-orange-300" },
  drain:   { label: "Broken Drain",    icon: Droplets, badge: "bg-blue-100 text-blue-700 dark:bg-blue-950 dark:text-blue-300" },
  general: { label: "General Pollution",icon: Waves,   badge: "bg-green-100 text-green-700 dark:bg-green-950 dark:text-green-300" },
} as const;

const SEV_DOT: Record<string, string> = { low: "bg-green-400", medium: "bg-amber-400", high: "bg-red-500" };
const STATUS_BADGE: Record<string, string> = {
  reported:     "bg-slate-100 text-slate-600 dark:bg-slate-800 dark:text-slate-300",
  acknowledged: "bg-amber-100 text-amber-700 dark:bg-amber-950/50 dark:text-amber-400",
  cleaned:      "bg-green-100 text-green-700 dark:bg-green-950/50 dark:text-green-400",
};

export default function ReportsList() {
  const { reports: all, ready } = useReports();
  const [search, setSearch] = useState("");
  const [cause, setCause] = useState("all");
  const [severity, setSeverity] = useState("all");
  const [showFilters, setShowFilters] = useState(false);

  const filtered = all.filter(r => {
    if (cause !== "all" && r.causeTag !== cause) return false;
    if (severity !== "all" && r.severity !== severity) return false;
    if (search) {
      const q = search.toLowerCase();
      if (!r.description.toLowerCase().includes(q) && !(r.location || "").toLowerCase().includes(q)) return false;
    }
    return true;
  });

  return (
    <div className="max-w-4xl mx-auto p-4 md:p-6 py-8">
      {/* Header */}
      <div className="flex items-center justify-between mb-6">
        <div>
          <h1 className="text-3xl font-extrabold">Activity Feed</h1>
          <p className="text-muted-foreground text-sm mt-0.5">All reports — live, real-time</p>
        </div>
        <Link href="/report">
          <Button className="gradient-ocean text-white border-0 shadow-md gap-2" size="sm">
            + Report
          </Button>
        </Link>
      </div>

      {/* Search & filters */}
      <div className="flex gap-2 mb-3">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
          <Input
            placeholder="Search reports…"
            className="pl-9"
            value={search}
            onChange={e => setSearch(e.target.value)}
            data-testid="search-input"
          />
        </div>
        <Button variant="outline" size="icon" onClick={() => setShowFilters(!showFilters)}>
          <SlidersHorizontal className="w-4 h-4" />
        </Button>
      </div>

      {showFilters && (
        <div className="flex flex-wrap gap-3 mb-5 p-4 bg-muted/50 border rounded-xl">
          <div className="flex flex-col gap-1">
            <span className="text-[10px] font-bold text-muted-foreground uppercase tracking-wide">Cause</span>
            <div className="flex gap-1.5">
              {["all", "dumping", "drain", "general"].map(c => (
                <button
                  key={c}
                  onClick={() => setCause(c)}
                  className={cn(
                    "px-2.5 py-1 rounded-lg text-[11px] font-semibold capitalize transition-all",
                    cause === c ? "bg-primary text-primary-foreground" : "bg-card border hover:bg-muted"
                  )}
                >
                  {c === "all" ? "All" : CAUSE[c as keyof typeof CAUSE]?.label || c}
                </button>
              ))}
            </div>
          </div>
          <div className="flex flex-col gap-1">
            <span className="text-[10px] font-bold text-muted-foreground uppercase tracking-wide">Severity</span>
            <div className="flex gap-1.5">
              {["all", "low", "medium", "high"].map(s => (
                <button
                  key={s}
                  onClick={() => setSeverity(s)}
                  className={cn(
                    "px-2.5 py-1 rounded-lg text-[11px] font-semibold capitalize transition-all",
                    severity === s ? "bg-primary text-primary-foreground" : "bg-card border hover:bg-muted"
                  )}
                >
                  {s}
                </button>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* Count */}
      <div className="text-xs text-muted-foreground mb-4">
        Showing <strong className="text-foreground">{filtered.length}</strong> report{filtered.length !== 1 ? "s" : ""}
        {!ready && <span className="ml-2 text-amber-500">● Loading…</span>}
        {ready && <span className="ml-2 text-green-500">● Live</span>}
      </div>

      {/* List */}
      {!ready ? (
        <div className="space-y-3">
          {[...Array(5)].map((_, i) => <div key={i} className="h-24 bg-muted rounded-xl animate-pulse" />)}
        </div>
      ) : filtered.length === 0 ? (
        <div className="bg-card border rounded-xl p-10 text-center text-muted-foreground">
          <Waves className="w-8 h-8 mx-auto opacity-30 mb-3" />
          <p className="font-medium">No reports match your filters</p>
        </div>
      ) : (
        <div className="space-y-3">
          {filtered.map(r => {
            const c = CAUSE[r.causeTag];
            return (
              <Link key={r.id} href={`/report/${r.id}`}>
                <div className="group bg-card border rounded-xl overflow-hidden hover:border-primary/40 hover:shadow-md transition-all cursor-pointer flex" data-testid={`report-item-${r.id}`}>
                  {r.photoUrl && (
                    <div className="w-28 md:w-36 shrink-0 overflow-hidden">
                      <img src={r.photoUrl} alt="Report" className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500" />
                    </div>
                  )}
                  <div className="flex-1 p-4 flex flex-col justify-between min-w-0">
                    <div>
                      <div className="flex flex-wrap gap-1.5 mb-2">
                        <span className={cn("text-[10px] font-bold px-2 py-0.5 rounded-full", c.badge)}>{c.label}</span>
                        <span className={cn("text-[10px] font-bold px-2 py-0.5 rounded-full capitalize", STATUS_BADGE[r.status])}>{r.status}</span>
                        <span className="flex items-center gap-1 text-[10px] capitalize text-muted-foreground">
                          <span className={cn("w-1.5 h-1.5 rounded-full", SEV_DOT[r.severity])} />
                          {r.severity}
                        </span>
                      </div>
                      <p className="text-sm text-muted-foreground line-clamp-2">{r.description}</p>
                    </div>
                    <div className="flex items-center justify-between mt-2">
                      <div className="flex items-center gap-1 text-xs text-muted-foreground">
                        <MapPin className="w-3 h-3" />
                        <span className="truncate max-w-[180px]">{r.location || `${r.latitude.toFixed(3)}, ${r.longitude.toFixed(3)}`}</span>
                      </div>
                      <div className="flex items-center gap-3 shrink-0">
                        <span className="flex items-center gap-1 text-xs text-muted-foreground">
                          <ThumbsUp className="w-3 h-3" />{r.upvotes}
                        </span>
                        <span className="text-xs text-muted-foreground">{formatDistanceToNow(new Date(r.createdAt), { addSuffix: true })}</span>
                      </div>
                    </div>
                  </div>
                </div>
              </Link>
            );
          })}
        </div>
      )}
    </div>
  );
}

import { useEffect, useState } from "react";
import { useParams, useLocation } from "wouter";
import { getReport, upvoteReport, Report } from "@/lib/db";
import { Map } from "@/components/Map";
import { Button } from "@/components/ui/button";
import {
  MapPin, ThumbsUp, Clock, CheckCircle2, Loader2, ArrowLeft,
  Trash2, Droplets, Waves, Shield, AlertTriangle
} from "lucide-react";
import { formatDistanceToNow, format } from "date-fns";
import { cn } from "@/lib/utils";
import { motion } from "framer-motion";

const CAUSE = {
  dumping: { label: "Illegal Dumping",  icon: Trash2,   badge: "bg-orange-100 text-orange-700 dark:bg-orange-950 dark:text-orange-300", color: "text-orange-500" },
  drain:   { label: "Broken Drain",     icon: Droplets, badge: "bg-blue-100 text-blue-700 dark:bg-blue-950 dark:text-blue-300",     color: "text-blue-500" },
  general: { label: "General Pollution",icon: Waves,    badge: "bg-green-100 text-green-700 dark:bg-green-950 dark:text-green-300", color: "text-green-500" },
} as const;

const STATUSES: { key: Report["status"]; label: string; icon: any; color: string; bg: string }[] = [
  { key: "reported",     label: "Reported",     icon: AlertTriangle, color: "text-slate-500",   bg: "bg-slate-100 dark:bg-slate-800" },
  { key: "acknowledged", label: "Acknowledged", icon: Shield,        color: "text-amber-500",   bg: "bg-amber-50 dark:bg-amber-950/30" },
  { key: "cleaned",      label: "Cleaned Up",   icon: CheckCircle2,  color: "text-green-500",   bg: "bg-green-50 dark:bg-green-950/30" },
];

export default function ReportDetail() {
  const { id } = useParams<{ id: string }>();
  const [, setLocation] = useLocation();
  const [report, setReport] = useState<Report | null | undefined>(undefined);
  const [upvoting, setUpvoting] = useState(false);
  const [upvoted, setUpvoted] = useState(false);

  useEffect(() => {
    getReport(id).then(r => setReport(r ?? null));
  }, [id]);

  const handleUpvote = async () => {
    if (!report || upvoted) return;
    setUpvoting(true);
    await upvoteReport(id);
    setReport(r => r ? { ...r, upvotes: r.upvotes + 1 } : r);
    setUpvoted(true);
    setUpvoting(false);
  };

  if (report === undefined) {
    return (
      <div className="flex items-center justify-center h-full p-12">
        <Loader2 className="w-8 h-8 animate-spin text-muted-foreground" />
      </div>
    );
  }

  if (report === null) {
    return (
      <div className="max-w-2xl mx-auto p-6 py-12 text-center">
        <AlertTriangle className="w-12 h-12 mx-auto text-muted-foreground/40 mb-4" />
        <h2 className="text-xl font-bold mb-2">Report not found</h2>
        <p className="text-muted-foreground mb-6">This report may have been removed or the link is incorrect.</p>
        <Button onClick={() => setLocation("/reports")}>Back to Feed</Button>
      </div>
    );
  }

  const c = CAUSE[report.causeTag];
  const currentStatusIdx = STATUSES.findIndex(s => s.key === report.status);

  return (
    <div className="max-w-3xl mx-auto p-4 md:p-6 py-8">
      {/* Back */}
      <button onClick={() => setLocation("/reports")} className="flex items-center gap-1.5 text-sm text-muted-foreground hover:text-foreground transition-colors mb-5">
        <ArrowLeft className="w-4 h-4" /> Back to feed
      </button>

      <motion.div initial={{ opacity: 0, y: 12 }} animate={{ opacity: 1, y: 0 }}>
        {/* Photo */}
        {report.photoUrl && (
          <div className="rounded-2xl overflow-hidden mb-6 aspect-video">
            <img src={report.photoUrl} alt="Report" className="w-full h-full object-cover" />
          </div>
        )}

        {/* Tags */}
        <div className="flex flex-wrap gap-2 mb-4">
          <span className={cn("flex items-center gap-1.5 text-sm font-semibold px-3 py-1.5 rounded-full", c.badge)}>
            <c.icon className="w-4 h-4" /> {c.label}
          </span>
          <span className={cn(
            "text-sm font-semibold px-3 py-1.5 rounded-full capitalize",
            report.severity === "high" ? "bg-red-100 text-red-700 dark:bg-red-950 dark:text-red-300" :
            report.severity === "medium" ? "bg-amber-100 text-amber-700 dark:bg-amber-950 dark:text-amber-300" :
            "bg-green-100 text-green-700 dark:bg-green-950 dark:text-green-300"
          )}>
            {report.severity} severity
          </span>
        </div>

        {/* Description */}
        <h1 className="text-xl font-bold mb-2 leading-snug">{report.description.slice(0, 80)}{report.description.length > 80 ? "…" : ""}</h1>
        <p className="text-muted-foreground text-sm mb-6 leading-relaxed">{report.description}</p>

        {/* Meta */}
        <div className="flex flex-wrap gap-4 text-sm text-muted-foreground mb-6">
          <div className="flex items-center gap-1.5"><MapPin className="w-4 h-4" /> {report.location || `${report.latitude.toFixed(4)}, ${report.longitude.toFixed(4)}`}</div>
          <div className="flex items-center gap-1.5"><Clock className="w-4 h-4" /> {formatDistanceToNow(new Date(report.createdAt), { addSuffix: true })}</div>
          <div className="text-xs">{format(new Date(report.createdAt), "PPP · p")}</div>
        </div>

        {/* Upvote */}
        <Button
          variant={upvoted ? "default" : "outline"}
          className={cn("gap-2 mb-8", upvoted && "gradient-ocean text-white border-0")}
          onClick={handleUpvote}
          disabled={upvoting || upvoted}
          data-testid="upvote-button"
        >
          {upvoting ? <Loader2 className="w-4 h-4 animate-spin" /> : <ThumbsUp className="w-4 h-4" />}
          {upvoted ? "Upvoted!" : "Upvote"} · {report.upvotes}
        </Button>

        {/* Status Timeline */}
        <div className="bg-card border rounded-2xl p-5 mb-6">
          <h2 className="font-bold mb-4 text-sm">Resolution Status</h2>
          <div className="relative">
            {/* Progress line */}
            <div className="absolute left-5 top-5 bottom-5 w-0.5 bg-border" />
            <div
              className="absolute left-5 top-5 w-0.5 bg-primary transition-all duration-700"
              style={{ height: `${(currentStatusIdx / (STATUSES.length - 1)) * 100}%` }}
            />
            <div className="space-y-5">
              {STATUSES.map((s, i) => {
                const done = i <= currentStatusIdx;
                const current = i === currentStatusIdx;
                return (
                  <div key={s.key} className="flex items-start gap-4">
                    <div className={cn(
                      "w-10 h-10 rounded-full flex items-center justify-center shrink-0 border-2 transition-all",
                      done ? (current ? "border-primary bg-primary text-primary-foreground" : "border-primary/40 bg-primary/10") : "border-border bg-card text-muted-foreground"
                    )}>
                      <s.icon className="w-4 h-4" />
                    </div>
                    <div className="pt-1.5">
                      <div className={cn("font-semibold text-sm", done ? "text-foreground" : "text-muted-foreground")}>{s.label}</div>
                      {current && <div className="text-xs text-primary font-medium mt-0.5">Current status</div>}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        </div>

        {/* Mini map */}
        <div className="rounded-2xl overflow-hidden border mb-6 h-52">
          <Map reports={[]} height="100%" zoom={15} singleReport={report} />
        </div>

        {/* Authority info */}
        <div className="bg-blue-50 dark:bg-blue-950/20 border border-blue-200 dark:border-blue-900 rounded-xl p-4 text-sm">
          <div className="flex items-center gap-2 mb-2">
            <Shield className="w-4 h-4 text-blue-500" />
            <span className="font-semibold">Report forwarded to authorities</span>
          </div>
          <p className="text-muted-foreground text-xs">This report was automatically sent to <strong>MCGM, MPCB, and BMC</strong> based on its cause classification. Typical response time: 24–72 hours.</p>
        </div>
      </motion.div>
    </div>
  );
}

