          <div className="flex items-center gap-2 mb-2">
            <Shield className="w-4 h-4 text-blue-500" />
            <span className="font-semibold">Report forwarded to authorities</span>
          </div>
          <p className="text-muted-foreground text-xs">
            This report was automatically sent to <strong>MCGM, MPCB, and BMC</strong> based on its cause classification.
            Typical response time: 24–72 hours.
          </p>
        </div>
      </motion.div>
    </div>
  );
}

