import { initializeApp, getApps, getApp } from "firebase/app";
import { getFirestore } from "firebase/firestore";
import { getStorage } from "firebase/storage";
import { getAuth } from "firebase/auth";

const cfg = {
  apiKey: import.meta.env.VITE_FIREBASE_API_KEY,
  authDomain: import.meta.env.VITE_FIREBASE_AUTH_DOMAIN,
  projectId: import.meta.env.VITE_FIREBASE_PROJECT_ID,
  storageBucket: import.meta.env.VITE_FIREBASE_STORAGE_BUCKET,
  messagingSenderId: import.meta.env.VITE_FIREBASE_MESSAGING_SENDER_ID,
  appId: import.meta.env.VITE_FIREBASE_APP_ID,
};

export const isFirebaseConfigured =
  !!cfg.apiKey && cfg.apiKey !== "mock-key" && !!cfg.projectId && cfg.projectId !== "mock-project";

const app = !getApps().length ? initializeApp(cfg) : getApp();
export const db = getFirestore(app);
export const storage = getStorage(app);
export const auth = getAuth(app);

import { createContext, useContext, useEffect, useState, ReactNode } from "react";
import {
  GoogleAuthProvider, signInWithPopup, signOut as fbSignOut,
  onAuthStateChanged, User,
} from "firebase/auth";
import { auth, isFirebaseConfigured } from "./firebase";

export interface AuthUser {
  uid: string;
  email: string | null;
  displayName: string | null;
  photoURL: string | null;
}

interface AuthCtx {
  user: AuthUser | null;
  loading: boolean;
  signInWithGoogle: () => Promise<void>;
  signOut: () => Promise<void>;
  isDemoMode: boolean;
}

const DEMO_USER: AuthUser = {
  uid: "demo-user-riplle",
  email: "demo@riplle.app",
  displayName: "Demo User",
  photoURL: null,
};

export const AuthContext = createContext<AuthCtx>({
  user: null,
  loading: true,
  signInWithGoogle: async () => {},
  signOut: async () => {},
  isDemoMode: false,
});

export function useAuth() {
  return useContext(AuthContext);
}

function toAuthUser(u: User): AuthUser {
  return { uid: u.uid, email: u.email, displayName: u.displayName, photoURL: u.photoURL };
}

export function createAuthValue(): AuthCtx {
  // This is called inside AuthProvider — we use plain React hooks there.
  // Keeping this file as a pure helper.
  return {} as AuthCtx;
}

/* Hook used inside AuthProvider */
export function useAuthState(): AuthCtx {
  const [user, setUser] = useState<AuthUser | null>(null);
  const [loading, setLoading] = useState(true);
  const [isDemoMode, setIsDemoMode] = useState(false);

  useEffect(() => {
    if (!isFirebaseConfigured) {
      setLoading(false);
      return;
    }
    const unsub = onAuthStateChanged(auth, (u) => {
      setUser(u ? toAuthUser(u) : null);
      setLoading(false);
    });
    return unsub;
  }, []);

  const signInWithGoogle = async () => {
    if (!isFirebaseConfigured) {
      setUser(DEMO_USER);
      setIsDemoMode(true);
      return;
    }
    try {
      const provider = new GoogleAuthProvider();
      provider.setCustomParameters({ prompt: "select_account" });
      const result = await signInWithPopup(auth, provider);
      setUser(toAuthUser(result.user));
      setIsDemoMode(false);
    } catch (err: any) {
      // If auth domain not configured, fall back to demo
      if (err.code === "auth/configuration-not-found" || err.code === "auth/unauthorized-domain" || err.code === "auth/operation-not-allowed") {
        setUser(DEMO_USER);
        setIsDemoMode(true);
      } else {
        throw err;
      }
    }
  };

  const signOut = async () => {
    if (!isFirebaseConfigured || isDemoMode) {
      setUser(null);
      setIsDemoMode(false);
      return;
    }
    await fbSignOut(auth);
    setUser(null);
  };

  return { user, loading, signInWithGoogle, signOut, isDemoMode };
}

import { useEffect, useState, useCallback } from "react";
import {
  collection, onSnapshot, query, orderBy,
  addDoc, updateDoc, doc, getDoc, increment, serverTimestamp, where, getDocs
} from "firebase/firestore";
import { ref, uploadBytesResumable, getDownloadURL } from "firebase/storage";
import { db, storage, isFirebaseConfigured } from "./firebase";

export interface Report {
  id: string;
  photoUrl: string;
  latitude: number;
  longitude: number;
  causeTag: "dumping" | "drain" | "general";
  severity: "low" | "medium" | "high";
  description: string;
  status: "reported" | "acknowledged" | "cleaned";
  upvotes: number;
  createdAt: number;
  reporterEmail?: string;
  location?: string;
  /* v2 fields */
  highRisk?: boolean;
  nearestBeach?: string;
  userId?: string;
  userDisplayName?: string;
}

export interface Stats {
  total: number;
  dumping: number;
  drain: number;
  general: number;
  reported: number;
  acknowledged: number;
  cleaned: number;
  thisWeek: number;
  highRisk: number;
}

/* ─── Coastal Proximity Engine ──────────────────────────────────────────── */
const COASTAL_POINTS = [
  { lat: 19.1258, lng: 72.8076, name: "Versova Beach" },
  { lat: 19.0990, lng: 72.8296, name: "Juhu Beach" },
  { lat: 19.0540, lng: 72.8258, name: "Carter Road, Bandra" },
  { lat: 19.0406, lng: 72.8196, name: "Bandstand, Bandra" },
  { lat: 18.9549, lng: 72.8154, name: "Girgaon Chowpatty" },
  { lat: 18.9432, lng: 72.8240, name: "Marine Drive" },
  { lat: 18.9823, lng: 72.8125, name: "Worli Seaface" },
  { lat: 18.9763, lng: 72.8085, name: "Haji Ali" },
  { lat: 19.0418, lng: 72.8400, name: "Mahim Bay" },
  { lat: 19.2021, lng: 72.7851, name: "Manori Beach" },
  { lat: 18.8958, lng: 72.8120, name: "Colaba Coast" },
  { lat: 19.1025, lng: 72.8322, name: "Madh Island" },
];

const COASTAL_RADIUS_KM = 0.5;

function haversineKm(lat1: number, lng1: number, lat2: number, lng2: number): number {
  const R = 6371;
  const dLat = ((lat2 - lat1) * Math.PI) / 180;
  const dLng = ((lng2 - lng1) * Math.PI) / 180;
  const a =
    Math.sin(dLat / 2) ** 2 +
    Math.cos((lat1 * Math.PI) / 180) * Math.cos((lat2 * Math.PI) / 180) * Math.sin(dLng / 2) ** 2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
}

export function checkCoastalProximity(lat: number, lng: number): { nearCoast: boolean; nearestBeach?: string; distanceKm?: number } {
  let closest: { name: string; dist: number } | null = null;
  for (const pt of COASTAL_POINTS) {
    const dist = haversineKm(lat, lng, pt.lat, pt.lng);
    if (!closest || dist < closest.dist) closest = { name: pt.name, dist };
  }
  if (closest && closest.dist <= COASTAL_RADIUS_KM) {
    return { nearCoast: true, nearestBeach: closest.name, distanceKm: closest.dist };
  }
  return { nearCoast: false };
}

/* ─── Seed data ──────────────────────────────────────────────────────────── */
export const SEED: Report[] = [
  {
    id: "s1", photoUrl: "https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=600&q=80",
    latitude: 19.1253, longitude: 72.8081, causeTag: "dumping", severity: "high",
    description: "Industrial waste and plastic bags dumped right beside Versova beach. Smell is unbearable.",
    status: "reported", upvotes: 24, createdAt: Date.now() - 86_400_000, location: "Versova Beach, Andheri W",
    highRisk: true, nearestBeach: "Versova Beach",
  },
  {
    id: "s2", photoUrl: "https://images.unsplash.com/photo-1574482620826-7f57e68b95d4?w=600&q=80",
    latitude: 18.9768, longitude: 72.8090, causeTag: "drain", severity: "high",
    description: "Broken sewage drain near Haji Ali discharging black water directly into the sea continuously.",
    status: "acknowledged", upvotes: 18, createdAt: Date.now() - 172_800_000, location: "Haji Ali, Mumbai",
    highRisk: true, nearestBeach: "Haji Ali",
  },
  {
    id: "s3", photoUrl: "https://images.unsplash.com/photo-1567427017947-545c5f8d16ad?w=600&q=80",
    latitude: 19.0990, longitude: 72.8296, causeTag: "general", severity: "low",
    description: "Heavy plastic and debris washed ashore at Juhu Beach after last night's rain.",
    status: "cleaned", upvotes: 31, createdAt: Date.now() - 259_200_000, location: "Juhu Beach, Mumbai",
    highRisk: false,
  },
  {
    id: "s4", photoUrl: "https://images.unsplash.com/photo-1611280122778-a3ef06467b3a?w=600&q=80",
    latitude: 19.102, longitude: 72.865, causeTag: "drain", severity: "high",
    description: "Broken manhole near Borivali creek overflowing with sewage. Children at risk.",
    status: "reported", upvotes: 9, createdAt: Date.now() - 345_600_000, location: "Borivali Creek, Mumbai",
    highRisk: false,
  },
  {
    id: "s5", photoUrl: "https://images.unsplash.com/photo-1532187863486-abf9dbad1b69?w=600&q=80",
    latitude: 18.9826, longitude: 72.8128, causeTag: "dumping", severity: "medium",
    description: "Construction debris illegally dumped near Worli seaface. Materials sliding into the water.",
    status: "acknowledged", upvotes: 14, createdAt: Date.now() - 432_000_000, location: "Worli Seaface, Mumbai",
    highRisk: true, nearestBeach: "Worli Seaface",
  },
];

/* ─── In-memory store ────────────────────────────────────────────────────── */
let memReports: Report[] = [...SEED];
const memListeners = new Set<() => void>();
const notifyMem = () => memListeners.forEach(fn => fn());

/* ─── Hooks ──────────────────────────────────────────────────────────────── */

export const useReports = () => {
  const [reports, setReports] = useState<Report[]>(memReports);
  const [ready, setReady] = useState(false);

  useEffect(() => {
    if (!isFirebaseConfigured) {
      setReports([...memReports]);
      setReady(true);
      const refresh = () => setReports([...memReports]);
      memListeners.add(refresh);
      return () => { memListeners.delete(refresh); };
    }
    const q = query(collection(db, "reports"), orderBy("createdAt", "desc"));
    const unsub = onSnapshot(q,
      (snap) => {
        const data = snap.docs.map(d => ({ id: d.id, ...d.data() } as Report));
        setReports(data.length > 0 ? data : [...memReports]);
        setReady(true);
      },
      () => { setReports([...memReports]); setReady(true); }
    );
    return unsub;
  }, []);

  return { reports, ready };
};

export const useUserReports = (userId: string | undefined) => {
  const { reports, ready } = useReports();
  if (!userId) return { reports: [], ready };
  const userReports = reports.filter(r => r.userId === userId);
  return { reports: userReports, ready };
};

export const useStats = () => {
  const [stats, setStats] = useState<Stats | null>(null);

  const compute = useCallback((list: Report[]): Stats => {
    const week = Date.now() - 7 * 86_400_000;
    return {
      total: list.length,
      dumping: list.filter(r => r.causeTag === "dumping").length,
      drain: list.filter(r => r.causeTag === "drain").length,
      general: list.filter(r => r.causeTag === "general").length,
      reported: list.filter(r => r.status === "reported").length,
      acknowledged: list.filter(r => r.status === "acknowledged").length,
      cleaned: list.filter(r => r.status === "cleaned").length,
      thisWeek: list.filter(r => r.createdAt > week).length,
      highRisk: list.filter(r => r.highRisk).length,
    };
  }, []);

  useEffect(() => {
    if (!isFirebaseConfigured) {
      setStats(compute(memReports));
      const refresh = () => setStats(compute([...memReports]));
      memListeners.add(refresh);
      return () => { memListeners.delete(refresh); };
    }
    const q = query(collection(db, "reports"), orderBy("createdAt", "desc"));
    const unsub = onSnapshot(q,
      (snap) => {
        const data = snap.docs.map(d => ({ id: d.id, ...d.data() } as Report));
        setStats(compute(data.length > 0 ? data : memReports));
      },
      () => { setStats(compute(memReports)); }
    );
    return unsub;
  }, [compute]);

  return stats;
};

/* ─── Mutations ──────────────────────────────────────────────────────────── */

export const uploadPhoto = async (file: File): Promise<string> => {
  if (!isFirebaseConfigured) return SEED[0].photoUrl;
  const fileRef = ref(storage, `reports/${Date.now()}_${file.name}`);
  const snap = await uploadBytesResumable(fileRef, file);
  return getDownloadURL(snap.ref);
};

export const createReport = async (
  data: Omit<Report, "id" | "createdAt" | "upvotes" | "status" | "photoUrl" | "highRisk" | "nearestBeach">,
  file?: File | null
): Promise<Report> => {
  let photoUrl = SEED[0].photoUrl;
  if (file) {
    try { photoUrl = await uploadPhoto(file); } catch { }
  }

  /* ─── Coastal Proximity Escalation ─── */
  const coastal = checkCoastalProximity(data.latitude, data.longitude);
  const highRisk = coastal.nearCoast && (data.causeTag === "dumping" || data.causeTag === "drain");
  const finalSeverity = highRisk ? "high" : data.severity;

  const payload: Omit<Report, "id"> = {
    ...data,
    photoUrl,
    severity: finalSeverity,
    highRisk,
    nearestBeach: coastal.nearestBeach,
    createdAt: Date.now(),
    upvotes: 0,
    status: "reported",
  };

  if (!isFirebaseConfigured) {
    const r: Report = { ...payload, id: `local_${Date.now()}` };
    memReports = [r, ...memReports];
    notifyMem();
    return r;
  }

  try {
    const docRef = await addDoc(collection(db, "reports"), {
      ...payload,
      createdAt: serverTimestamp(),
    });
    const r: Report = { ...payload, id: docRef.id };
    memReports = [r, ...memReports];
    notifyMem();
    return r;
  } catch (err) {
    console.warn("Firebase write failed, using local fallback", err);
    const r: Report = { ...payload, id: `local_${Date.now()}` };
    memReports = [r, ...memReports];
    notifyMem();
    return r;
  }
};

export const upvoteReport = async (id: string) => {
  memReports = memReports.map(r => r.id === id ? { ...r, upvotes: r.upvotes + 1 } : r);
  notifyMem();
  if (!isFirebaseConfigured) return;
  try { await updateDoc(doc(db, "reports", id), { upvotes: increment(1) }); } catch { }
};

export const getReport = async (id: string): Promise<Report | undefined> => {
  if (!isFirebaseConfigured) return memReports.find(r => r.id === id);
  try {
    const snap = await getDoc(doc(db, "reports", id));
    if (snap.exists()) return { id: snap.id, ...snap.data() } as Report;
  } catch { }
  return memReports.find(r => r.id === id);
};

export const getWeeklyTrend = async (): Promise<{ day: string; reports: number }[]> => {
  const days = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"];
  const now = new Date();
  const result = days.map((_, i) => {
    const d = new Date(now);
    d.setDate(d.getDate() - (6 - i));
    return { day: days[d.getDay()], date: d, reports: 0 };
  });
  const weekAgo = Date.now() - 7 * 86_400_000;
  let reports = memReports.filter(r => r.createdAt > weekAgo);
  if (isFirebaseConfigured) {
    try {
      const snap = await getDocs(query(collection(db, "reports"), where("createdAt", ">", weekAgo)));
      const fb = snap.docs.map(d => d.data() as Report);
      if (fb.length > 0) reports = fb;
    } catch { }
  }
  reports.forEach(r => {
    const d = new Date(r.createdAt);
    const idx = result.findIndex(x => x.date.toDateString() === d.toDateString());
    if (idx >= 0) result[idx].reports++;
  });
  return result.map(({ day, reports }) => ({ day, reports }));
};

/* ─── CSV Export ─────────────────────────────────────────────────────────── */
export function exportReportsCSV(reports: Report[], filename?: string) {
  const headers = [
    "Report ID", "Date", "Time", "Location", "Latitude", "Longitude",
    "Cause", "Severity", "Status", "High Risk", "Nearest Beach",
    "Description", "Upvotes", "Reporter"
  ];
  const rows = reports.map(r => [
    r.id,
    new Date(r.createdAt).toLocaleDateString("en-IN"),
    new Date(r.createdAt).toLocaleTimeString("en-IN"),
    (r.location || "").replace(/,/g, ";"),
    r.latitude.toFixed(6),
    r.longitude.toFixed(6),
    r.causeTag,
    r.severity,
    r.status,
    r.highRisk ? "YES" : "NO",
    r.nearestBeach || "",
    `"${r.description.replace(/"/g, '""')}"`,
    r.upvotes,
    r.userDisplayName || r.reporterEmail || "Anonymous",
  ]);
  const csv = [headers.join(","), ...rows.map(row => row.join(","))].join("\n");
  const blob = new Blob([csv], { type: "text/csv;charset=utf-8;" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = filename || `riplle-reports-${new Date().toISOString().split("T")[0]}.csv`;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

