                    </div>
                  </div>
                </div>
              </Popup>
            </Marker>
          ))}
        </MarkerClusterGroup>
      )}

      {singleReport && (
        <Marker position={[singleReport.latitude, singleReport.longitude]} icon={makeIcon(singleReport)} />
      )}
