export default function ReportForm() {
  const [, setLocation] = useLocation();
  const { user } = useAuth();
  const [step, setStep] = useState(1);
  const [submitting, setSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(false);
  const [submittedId, setSubmittedId] = useState<string | null>(null);

  const [photo, setPhoto] = useState<File | null>(null);
  const [photoPreview, setPhotoPreview] = useState<string | null>(null);
  const [coords, setCoords] = useState<{ lat: number; lng: number } | null>(null);
  const [locating, setLocating] = useState(false);
  const [locationLabel, setLocationLabel] = useState<string>("");

  const [cause, setCause] = useState<"dumping" | "drain" | "general">("dumping");
  const [severity, setSeverity] = useState<"low" | "medium" | "high">("medium");
  const [description, setDescription] = useState("");

  /* ── Coastal escalation state ── */
  const [nearCoast, setNearCoast] = useState(false);
  const [nearestBeach, setNearestBeach] = useState<string | undefined>(undefined);
  const [coastalEscalated, setCoastalEscalated] = useState(false);

  const fileRef = useRef<HTMLInputElement>(null);

  /* Re-evaluate coastal warning whenever cause OR coords change */
  useEffect(() => {
    if (!coords) return;
    const result = checkCoastalProximity(coords.lat, coords.lng);
    const escalate = result.nearCoast && (cause === "dumping" || cause === "drain");
    setNearCoast(result.nearCoast);
    setNearestBeach(result.nearestBeach);
    setCoastalEscalated(escalate);
    if (escalate) setSeverity("high");
  }, [coords, cause]);

  const handlePhoto = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setPhoto(file);
    setPhotoPreview(URL.createObjectURL(file));
  };

  const getLocation = () => {
    setLocating(true);
    if (!navigator.geolocation) {
      setCoords({ lat: 18.9388, lng: 72.8354 });
      setLocationLabel("Mumbai (default)");
      setLocating(false);
      return;
    }
    navigator.geolocation.getCurrentPosition(
      async (pos) => {
        const { latitude: lat, longitude: lng } = pos.coords;
        setCoords({ lat, lng });
        setLocating(false);
        try {
          const res = await fetch(`https://nominatim.openstreetmap.org/reverse?lat=${lat}&lon=${lng}&format=json`);
          const data = await res.json();
          setLocationLabel(data.display_name?.split(",").slice(0, 2).join(", ") || `${lat.toFixed(4)}, ${lng.toFixed(4)}`);
        } catch {
          setLocationLabel(`${lat.toFixed(4)}, ${lng.toFixed(4)}`);
        }
      },
      () => {
        setCoords({ lat: 18.9388, lng: 72.8354 });
        setLocationLabel("Mumbai (approximate)");
        setLocating(false);
      },
      { timeout: 8000 }
    );
  };

  const submit = async () => {
    if (!coords) return;
    setSubmitting(true);
    try {
      const report = await createReport(
        {
          latitude: coords.lat,
          longitude: coords.lng,
          causeTag: cause,
          severity,
          description,
          location: locationLabel,
          userId: user?.uid,
          userDisplayName: user?.displayName || undefined,
          reporterEmail: user?.email || undefined,
        },
        photo
      );
