const SEV_ORDER = { high: 0, medium: 1, low: 2 };
const STATUS_ORDER = { reported: 0, acknowledged: 1, cleaned: 2 };

function ReportsTable({ reports, emptyMessage }: { reports: Report[]; emptyMessage: string }) {
  const [sortKey, setSortKey] = useState<SortKey>("createdAt");
  const [sortAsc, setSortAsc] = useState(false);
  const [expanded, setExpanded] = useState<string | null>(null);

  const sorted = useMemo(() => {
    return [...reports].sort((a, b) => {
      let cmp = 0;
      if (sortKey === "createdAt") cmp = a.createdAt - b.createdAt;
      else if (sortKey === "upvotes") cmp = a.upvotes - b.upvotes;
      else if (sortKey === "severity") cmp = SEV_ORDER[a.severity] - SEV_ORDER[b.severity];
      else if (sortKey === "status") cmp = STATUS_ORDER[a.status] - STATUS_ORDER[b.status];
      return sortAsc ? cmp : -cmp;
    });
  }, [reports, sortKey, sortAsc]);

  const toggleSort = (key: SortKey) => {
    if (sortKey === key) setToggleSort(!sortAsc);
    else { setSortKey(key); setSortAsc(false); }
  };
  function setToggleSort(v: boolean) { setSortAsc(v); }

  const SortBtn = ({ k, label }: { k: SortKey; label: string }) => (
    <button
      onClick={() => toggleSort(k)}
      className={cn("flex items-center gap-1 text-[10px] font-bold uppercase tracking-wide hover:text-foreground transition-colors", sortKey === k ? "text-primary" : "text-muted-foreground")}
    >
      {label}<ArrowUpDown className="w-3 h-3" />
    </button>
  );

  if (reports.length === 0) {
    return (
      <div className="text-center py-10 text-muted-foreground text-sm">
        <Activity className="w-8 h-8 mx-auto opacity-30 mb-3" />{emptyMessage}
      </div>
    );
  }

  const CAUSE_BADGE: Record<string, string> = {
    dumping: "bg-orange-100 text-orange-700 dark:bg-orange-950 dark:text-orange-300",
    drain:   "bg-blue-100 text-blue-700 dark:bg-blue-950 dark:text-blue-300",
    general: "bg-green-100 text-green-700 dark:bg-green-950 dark:text-green-300",
  };
  const SEV_BADGE: Record<string, string> = {
    high: "bg-red-100 text-red-700 dark:bg-red-950 dark:text-red-300",
    medium: "bg-amber-100 text-amber-700 dark:bg-amber-950 dark:text-amber-300",
    low: "bg-green-100 text-green-700 dark:bg-green-950 dark:text-green-300",
  };

  return (
    <div className="overflow-x-auto rounded-xl border">
      <table className="w-full text-sm">
        <thead className="bg-muted/50 border-b">
          <tr>
            <th className="text-left px-4 py-3"><SortBtn k="createdAt" label="Date" /></th>
            <th className="text-left px-4 py-3 hidden md:table-cell"><span className="text-[10px] font-bold uppercase tracking-wide text-muted-foreground">Location</span></th>
            <th className="text-left px-4 py-3"><span className="text-[10px] font-bold uppercase tracking-wide text-muted-foreground">Cause</span></th>
            <th className="text-left px-4 py-3"><SortBtn k="severity" label="Severity" /></th>
            <th className="text-left px-4 py-3"><SortBtn k="status" label="Status" /></th>
            <th className="text-right px-4 py-3"><SortBtn k="upvotes" label="Votes" /></th>
            <th className="px-4 py-3" />
          </tr>
        </thead>
        <tbody className="divide-y">
          {sorted.map(r => (
            <>
              <tr
                key={r.id}
                className={cn("hover:bg-muted/30 transition-colors cursor-pointer", r.highRisk && "bg-red-50/60 dark:bg-red-950/10")}
                onClick={() => setExpanded(expanded === r.id ? null : r.id)}
              >
                <td className="px-4 py-3 text-xs text-muted-foreground whitespace-nowrap">
                  {r.highRisk && <span className="inline-block w-2 h-2 bg-red-500 rounded-full mr-1.5 animate-pulse" />}
                  {new Date(r.createdAt).toLocaleDateString("en-IN")}
                </td>
                <td className="px-4 py-3 text-xs text-muted-foreground hidden md:table-cell max-w-[140px] truncate">{r.location || "—"}</td>
                <td className="px-4 py-3">
                  <span className={cn("text-[10px] font-bold px-2 py-0.5 rounded-full capitalize", CAUSE_BADGE[r.causeTag])}>{r.causeTag}</span>
                </td>
                <td className="px-4 py-3">
                  <span className={cn("text-[10px] font-bold px-2 py-0.5 rounded-full capitalize", SEV_BADGE[r.severity])}>{r.severity}</span>
                </td>
                <td className="px-4 py-3">
                  <span className={cn(
                    "text-[10px] font-bold px-2 py-0.5 rounded-full capitalize",
                    r.status === "cleaned" ? "bg-green-100 text-green-700 dark:bg-green-950 dark:text-green-300" :
                    r.status === "acknowledged" ? "bg-amber-100 text-amber-700 dark:bg-amber-950 dark:text-amber-300" :
                    "bg-slate-100 text-slate-600 dark:bg-slate-800 dark:text-slate-300"
                  )}>{r.status}</span>
                </td>
                <td className="px-4 py-3 text-right text-xs font-medium">👍 {r.upvotes}</td>
                <td className="px-4 py-3">
                  {expanded === r.id ? <ChevronUp className="w-4 h-4 text-muted-foreground" /> : <ChevronDown className="w-4 h-4 text-muted-foreground" />}
                </td>
              </tr>
              {expanded === r.id && (
                <tr key={`${r.id}-expanded`} className={cn("border-b", r.highRisk ? "bg-red-50/80 dark:bg-red-950/20" : "bg-muted/20")}>
                  <td colSpan={7} className="px-4 py-3">
                    <div className="flex flex-col md:flex-row gap-4">
                      {r.photoUrl && <img src={r.photoUrl} alt="" className="w-32 h-20 object-cover rounded-lg shrink-0" />}
                      <div className="text-xs text-muted-foreground flex-1 space-y-1">
                        <p className="text-foreground">{r.description}</p>
                        {r.highRisk && <p className="text-red-600 dark:text-red-400 font-semibold">🚨 HIGH RISK — near {r.nearestBeach}</p>}
                        <div className="flex gap-4 mt-2">
                          <Link href={`/report/${r.id}`}><span className="text-primary hover:underline text-xs font-medium">View full report →</span></Link>
                        </div>
                      </div>
                    </div>
                  </td>
                </tr>
              )}
            </>
          ))}
        </tbody>
      </table>
    </div>
  );
}

