  const [causeFocus, setCauseFocus] = useState<string | null>(null);
  const [exporting, setExporting] = useState(false);

  useEffect(() => { getWeeklyTrend().then(setWeekly); }, []);

  const myReports = useMemo(() => reports.filter(r => r.userId === user?.uid), [reports, user?.uid]);
  const highRiskReports = useMemo(() => reports.filter(r => r.highRisk), [reports]);
  const filteredByPie = causeFocus ? reports.filter(r => r.causeTag === causeFocus) : reports;

  const resolution = stats && stats.total > 0 ? Math.round((stats.cleaned / stats.total) * 100) : 0;

  const pieData = stats ? [
    { name: "Illegal Dumping", value: stats.dumping, color: "#f97316", key: "dumping" },
    { name: "Broken Drains",   value: stats.drain,   color: "#3b82f6", key: "drain"   },
    { name: "Gen. Pollution",  value: stats.general, color: "#22c55e", key: "general" },
  ].filter(d => d.value > 0) : [];

  const handleExportCSV = () => {
    const toExport = tab === "my-reports" ? myReports : tab === "high-risk" ? highRiskReports : reports;
    setExporting(true);
    setTimeout(() => {
      exportReportsCSV(toExport, `riplle-${tab}-${new Date().toISOString().split("T")[0]}.csv`);
      setExporting(false);
    }, 400);
  };

  if (!stats || !ready) {
    return (
      <div className="max-w-6xl mx-auto p-6 py-12">
        <div className="animate-pulse space-y-6">
          <div className="h-8 bg-muted rounded w-48" />
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">{[...Array(4)].map((_, i) => <div key={i} className="h-28 bg-muted rounded-xl" />)}</div>
        </div>
      </div>
    );
  }

  const TABS: { id: TabId; label: string; icon: any; count?: number }[] = [
    { id: "overview",    label: "Overview",    icon: Activity,      count: stats.total },
    { id: "my-reports",  label: "My Reports",  icon: User,          count: myReports.length },
    { id: "high-risk",   label: "High Risk",   icon: AlertOctagon,  count: highRiskReports.length },
  ];

  return (
    <div className="max-w-6xl mx-auto p-4 md:p-6 py-8">
      {/* Header */}
      <div className="flex flex-wrap items-start justify-between gap-4 mb-6">
        <div>
          <h1 className="text-3xl font-extrabold">Impact Dashboard</h1>
          <p className="text-muted-foreground text-sm mt-1">Live data — updates in real-time via Firebase onSnapshot.</p>
        </div>
        <div className="flex items-center gap-2">
          <div className={cn("flex items-center gap-2 text-xs font-semibold px-3 py-1.5 rounded-full border",
            isFirebaseConfigured ? "text-green-700 bg-green-50 border-green-200 dark:bg-green-950/30 dark:text-green-400" : "text-amber-700 bg-amber-50 border-amber-200 dark:bg-amber-950/30 dark:text-amber-400"
          )}>
            <Wifi className="w-3.5 h-3.5" />{isFirebaseConfigured ? "Live – Firebase" : "Demo mode"}
          </div>
          <Button
            onClick={handleExportCSV}
            disabled={exporting}
            className="gradient-ocean text-white border-0 shadow-md gap-2 text-sm h-9"
          >
            {exporting ? <><Clock className="w-4 h-4 animate-spin" />Preparing…</> : <><FileSpreadsheet className="w-4 h-4" />Export CSV</>}
          </Button>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex gap-1.5 mb-6 bg-muted/50 p-1 rounded-xl w-fit">
        {TABS.map(t => (
          <button
            key={t.id}
            onClick={() => setTab(t.id)}
            className={cn(
              "flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all",
              tab === t.id ? "bg-card shadow-sm text-foreground" : "text-muted-foreground hover:text-foreground"
            )}
          >
            <t.icon className={cn("w-4 h-4", t.id === "high-risk" && t.count && t.count > 0 ? "text-red-500" : "")} />
            {t.label}
            {t.count !== undefined && (
              <span className={cn("text-[10px] font-bold px-1.5 py-0.5 rounded-full", tab === t.id ? "bg-primary text-primary-foreground" : "bg-muted text-muted-foreground")}>
                {t.count}
              </span>
            )}
          </button>
        ))}
      </div>

      <AnimatePresence mode="wait">
        <motion.div key={tab} initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0 }} transition={{ duration: 0.2 }}>

          {/* ── Overview Tab ── */}
          {tab === "overview" && (
            <div className="space-y-6">
              <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                <StatCard icon={Activity}      value={stats.total}      label="Total Reports"     color="bg-primary"        />
                <StatCard icon={AlertTriangle} value={stats.dumping}    label="Dumping Incidents" color="bg-orange-500"     />
                <StatCard icon={ShieldAlert}   value={stats.drain}      label="Broken Drains"     color="bg-blue-500"       />
                <StatCard icon={CheckCircle2}  value={resolution}       label="Resolution Rate"   color="bg-green-500" suffix="%" />
              </div>
              <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                <StatCard icon={AlertOctagon}  value={stats.highRisk}   label="High Risk (Coastal)" color="bg-red-500"     />
                <StatCard icon={TrendingUp}    value={stats.thisWeek}   label="This Week"         color="bg-violet-500"    />
                <StatCard icon={Clock}         value={stats.reported}   label="Pending Review"    color="bg-slate-500"     />
                <StatCard icon={CheckCircle2}  value={stats.cleaned}    label="Cleaned Up"        color="bg-emerald-500"   />
              </div>

              {/* Charts row */}
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                <Card>
                  <CardHeader className="pb-2">
                    <CardTitle className="text-base font-semibold">Reports by Cause</CardTitle>
                    <p className="text-xs text-muted-foreground">Click a slice to filter the table below</p>
                  </CardHeader>
                  <CardContent className="h-[260px]">
                    {pieData.length > 0 ? (
                      <ResponsiveContainer width="100%" height="100%">
                        <PieChart>
                          <Pie
                            data={pieData}
                            cx="50%" cy="50%"
                            innerRadius={65} outerRadius={95}
                            paddingAngle={4}
                            dataKey="value"
                            onClick={(_, index) => {
                              const key = pieData[index]?.key;
                              setCauseFocus(causeFocus === key ? null : key);
                              setActivePieIndex(activePieIndex === index ? null : index);
                            }}
                          >
                            {pieData.map((e, i) => (
                              <Cell
                                key={i}
                                fill={e.color}
                                strokeWidth={activePieIndex === i ? 3 : 0}
                                stroke={activePieIndex === i ? "#1e293b" : undefined}
                                opacity={activePieIndex !== null && activePieIndex !== i ? 0.4 : 1}
                                style={{ cursor: "pointer" }}
                              />
                            ))}
                          </Pie>
                          <Tooltip formatter={(v: number) => [`${v} report${v !== 1 ? "s" : ""}`, ""]} />
                          <Legend iconType="circle" iconSize={8} />
                        </PieChart>
                      </ResponsiveContainer>
                    ) : (
                      <div className="h-full flex flex-col items-center justify-center text-muted-foreground gap-2">
                        <Activity className="w-8 h-8 opacity-30" /><span className="text-sm">No reports yet</span>
                      </div>
                    )}
                  </CardContent>
                </Card>

                <Card>
                  <CardHeader className="pb-2">
                    <CardTitle className="text-base font-semibold">7-Day Activity</CardTitle>
                  </CardHeader>
                  <CardContent className="h-[260px]">
                    <ResponsiveContainer width="100%" height="100%">
                      <BarChart data={weekly} margin={{ top: 5, right: 10, left: -20, bottom: 5 }}>
                        <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" vertical={false} />
                        <XAxis dataKey="day" tick={{ fontSize: 11 }} axisLine={false} tickLine={false} />
                        <YAxis tick={{ fontSize: 11 }} axisLine={false} tickLine={false} allowDecimals={false} />
                        <Tooltip cursor={{ fill: "hsl(var(--muted))" }} />
                        <Bar dataKey="reports" fill="hsl(var(--primary))" radius={[6, 6, 0, 0]} maxBarSize={40} />
                      </BarChart>
                    </ResponsiveContainer>
                  </CardContent>
                </Card>
              </div>

              {/* Resolution pipeline */}
              <Card>
                <CardHeader className="pb-2">
                  <CardTitle className="text-base font-semibold">Resolution Pipeline</CardTitle>
                </CardHeader>
                <CardContent>
                  <div className="flex flex-col md:flex-row gap-6">
                    {[
                      { name: "Reported",     value: stats.reported,     color: "#94a3b8", bg: "bg-slate-50 dark:bg-slate-900/30 border-slate-200 dark:border-slate-700" },
                      { name: "Acknowledged", value: stats.acknowledged, color: "#f59e0b", bg: "bg-amber-50 dark:bg-amber-950/30 border-amber-200 dark:border-amber-800" },
                      { name: "Cleaned",      value: stats.cleaned,      color: "#22c55e", bg: "bg-green-50 dark:bg-green-950/30 border-green-200 dark:border-green-800" },
                    ].map(s => {
                      const pct = stats.total > 0 ? Math.round((s.value / stats.total) * 100) : 0;
                      return (
                        <div key={s.name} className={cn("flex-1 rounded-xl p-4 border", s.bg)}>
                          <div className="flex justify-between items-start mb-3">
                            <div className="text-sm font-semibold">{s.name}</div>
                            <div className="text-2xl font-extrabold" style={{ color: s.color }}>{s.value}</div>
                          </div>
                          <div className="h-1.5 bg-black/10 dark:bg-white/10 rounded-full overflow-hidden">
                            <div className="h-full rounded-full transition-all duration-700" style={{ width: `${pct}%`, backgroundColor: s.color }} />
                          </div>
                          <div className="text-[10px] text-muted-foreground mt-2">{pct}% of total</div>
                        </div>
                      );
                    })}
                  </div>
                </CardContent>
              </Card>

              {/* Filtered table from pie click */}
              {causeFocus && (
                <Card>
                  <CardHeader className="pb-2 flex-row items-center justify-between">
                    <CardTitle className="text-base font-semibold capitalize">
                      {causeFocus} Reports ({filteredByPie.length})
                    </CardTitle>
                    <Button variant="ghost" size="sm" className="text-xs" onClick={() => { setCauseFocus(null); setActivePieIndex(null); }}>
                      Clear filter ×
                    </Button>
                  </CardHeader>
                  <CardContent>
                    <ReportsTable reports={filteredByPie} emptyMessage="No reports for this cause." />
                  </CardContent>
                </Card>
              )}

              {/* CSV export promo */}
              <Card className="border-primary/20 bg-primary/5">
                <CardContent className="p-5 flex flex-col md:flex-row items-center gap-4">
                  <div className="w-12 h-12 gradient-ocean rounded-xl flex items-center justify-center shrink-0">
                    <FileSpreadsheet className="w-6 h-6 text-white" />
                  </div>
                  <div className="flex-1 text-center md:text-left">
                    <div className="font-bold">Export CSV for Municipal Planning</div>
                    <div className="text-sm text-muted-foreground mt-0.5">
                      Download all reports as a structured CSV file — ready to feed directly into trash route optimisation software.
                    </div>
                  </div>
                  <Button onClick={handleExportCSV} disabled={exporting} className="gradient-ocean text-white border-0 shadow-md gap-2 shrink-0">
                    {exporting ? <><Clock className="w-4 h-4 animate-spin" />Preparing…</> : <><Download className="w-4 h-4" />Download CSV</>}
                  </Button>
                </CardContent>
              </Card>
            </div>
          )}

          {/* ── My Reports Tab ── */}
          {tab === "my-reports" && (
            <div className="space-y-4">
              {myReports.length > 0 ? (
                <>
                  <div className="flex items-center justify-between">
                    <p className="text-sm text-muted-foreground">{myReports.length} report{myReports.length !== 1 ? "s" : ""} submitted by you</p>
                  </div>
                  <ReportsTable reports={myReports} emptyMessage="No reports found." />
                </>
              ) : (
                <div className="text-center py-16">
                  <User className="w-12 h-12 mx-auto text-muted-foreground/30 mb-4" />
                  <h3 className="font-semibold text-lg mb-2">No reports yet</h3>
                  <p className="text-muted-foreground text-sm mb-6 max-w-xs mx-auto">You haven't submitted any reports. Be the first to report pollution in your area.</p>
                  <Link href="/report"><Button className="gradient-ocean text-white border-0 shadow-md">Submit a Report</Button></Link>
                </div>
              )}
            </div>
          )}

          {/* ── High Risk Tab ── */}
          {tab === "high-risk" && (
            <div className="space-y-4">
              <div className="flex items-center gap-3 bg-red-50 dark:bg-red-950/20 border border-red-200 dark:border-red-800 rounded-xl p-4">
                <AlertOctagon className="w-5 h-5 text-red-500 shrink-0" />
                <div>
                  <div className="font-bold text-red-700 dark:text-red-400">Smart Proximity Escalation Active</div>
                  <div className="text-xs text-red-600 dark:text-red-400 mt-0.5">
                    Reports within 500m of Mumbai's coastline for Dumping or Drain incidents are automatically escalated to HIGH RISK.
                    These {highRiskReports.length} report{highRiskReports.length !== 1 ? "s" : ""} could contaminate the ocean during high tide.
                  </div>
                </div>
              </div>
              <ReportsTable reports={highRiskReports} emptyMessage="No high-risk reports — great news for Mumbai's coast!" />
            </div>
          )}
        </motion.div>
      </AnimatePresence>
    </div>
  );
}
